import 'package:equatable/equatable.dart'; enum DeviceType { phone, tablet, laptop, desktop, unknown } enum DeviceStatus { online, offline, connecting, busy } class DeviceEntity extends Equatable { final String deviceId; final String deviceName; final DeviceType type; final String ownerUserId; final DeviceStatus status; final String? fcmToken; final String? osVersion; final String? appVersion; final int? batteryLevel; const DeviceEntity({required this.deviceId, required this.deviceName, this.type = DeviceType.phone, required this.ownerUserId, this.status = DeviceStatus.offline, this.fcmToken, this.osVersion, this.appVersion, this.batteryLevel}); @override List<Object?> get props => [deviceId, status]; bool get isOnline => status == DeviceStatus.online; }
